mapper.select:
SELECT o.id, o.order_no, o.buyer_id, buyer.nickname AS buyer_nickname, o.seller_id, seller.nickname AS seller_nickname, o.product_id, p.title AS product_title, p.image AS product_image, o.address_id, a.receiver_name, a.receiver_phone, CONCAT(a.province, a.city, a.district, a.detail_address) AS full_address, o.quantity, o.total_price, o.status, o.tracking_number, o.remark, o.create_time, o.update_time FROM `order` o LEFT JOIN user buyer ON o.buyer_id = buyer.id LEFT JOIN user seller ON o.seller_id = seller.id LEFT JOIN product p ON o.product_id = p.id LEFT JOIN address a ON o.address_id = a.id WHERE o.deleted = 0
AND o.buyer_id = #{buyerId}
AND o.seller_id = #{sellerId}
AND o.status = #{status}
ORDER BY o.create_time DESC
